"""Command-line interface — one subcommand per phase.

Usage:

    # First-time setup
    sift init --root ./index
    sift seed --root ./index --from-json www.ato.gov.au_....json
    sift seed --root ./index --from-sitemap https://www.ato.gov.au/sitemap.xml

    # Each run is a sequence of resumable phases. New run-id is generated by
    # `plan` (or pass --run-id to resume an existing run).
    sift plan    --root ./index
    sift fetch   --root ./index --run-id <id> [--limit N] [--rate 2.0]
    sift extract --root ./index --run-id <id>
    sift commit  --root ./index --run-id <id>
    sift publish --root ./index --run-id <id>

    # One-shot convenience (still safe to interrupt at any phase)
    sift run --root ./index [--limit N]

    # Inspection
    sift status --root ./index
"""

